import os
import hashlib
from cryptography.fernet import Fernet

def encrypt_credit_card(cc_number):
    # Load the encryption key from the application config
    with open('encryption_key.txt', 'r') as f:
        encryption_key = f.read().strip()
    
    # Create a new Fernet object with the loaded key
    fer = Fernet(encryption_key)
    
    # Encrypt the credit card number using the Fernet object
    encrypted_cc_number = fer.encrypt(cc_number.encode())
    
    # Return the encrypted credit card number
    return encrypted_cc_number.decode()